def binary_file_operation(filepath: str, data: bytes = None, mode: str = 'r') -> bytes | bool | None:
    if mode == 'r':
        try:
            with open(filepath, 'rb') as f:
                content = f.read()
            return content
        except FileNotFoundError:
            return None
        except IOError:
            return None
    elif mode == 'w':
        if data is None or not isinstance(data, bytes):
            return None
        try:
            with open(filepath, 'wb') as f:
                f.write(data)
            return True
        except IOError:
            return None
    else:
        return None
